def {{nama_fungsi}}(coroutines, max_concurrency={{max_concurrency}}):
    """Run coroutines concurrently with concurrency limit.
    Returns list of (result_or_None, exception_or_None) tuples.
    Usage: results = await async_gather([coro1(), coro2(), ...])
    """
    semaphore = asyncio.Semaphore(max_concurrency)

    async def _limited(coro):
        async with semaphore:
            try:
                result = await coro
                return (result, None)
            except Exception as exc:
                return (None, exc)

    tasks = [asyncio.ensure_future(_limited(c)) for c in coroutines]
    return await asyncio.gather(*tasks)

class {{nama_class}}:
    """Thread-safe producer-consumer with bounded queue."""
    def __init__(self, maxsize={{queue_size}}):
        self._queue = queue.Queue(maxsize=maxsize)
        self._producers = []
        self._consumers = []
        self._running = False

    def add_producer(self, func, *args, **kwargs):
        """Register a producer function. func should call self.put(item)."""
        self._producers.append((func, args, kwargs))

    def add_consumer(self, func, *args, **kwargs):
        """Register a consumer function. func gets items via self.get()."""
        self._consumers.append((func, args, kwargs))

    def put(self, item, timeout=5):
        """Put item into queue (blocks if full)."""
        self._queue.put(item, timeout=timeout)

    def get(self, timeout=5):
        """Get item from queue (blocks if empty). Returns None if stopped."""
        try:
            return self._queue.get(timeout=timeout)
        except queue.Empty:
            return None

    def task_done(self):
        """Signal that a queued task is complete."""
        self._queue.task_done()

    def start(self):
        """Start all producer and consumer threads."""
        self._running = True
        for func, args, kwargs in self._producers:
            t = threading.Thread(target=func, args=args, kwargs=kwargs, daemon=True)
            t.start()
        for func, args, kwargs in self._consumers:
            t = threading.Thread(target=func, args=args, kwargs=kwargs, daemon=True)
            t.start()

    def stop(self):
        """Signal all threads to stop."""
        self._running = False

    @property
    def is_running(self):
        return self._running

    @property
    def size(self):
        return self._queue.qsize()

class {{nama_class}}:
    """Execute tasks with rate limiting. Thread-safe."""
    def __init__(self, rate={{rate}}, max_queue=1000):
        self.rate = rate
        self._interval = 1.0 / rate if rate > 0 else 0
        self._queue = queue.Queue(maxsize=max_queue)
        self._results = {}
        self._lock = threading.Lock()
        self._running = False
        self._thread = None

    def submit(self, task_id, func, *args, **kwargs):
        """Submit a task. Returns task_id for later retrieval."""
        self._queue.put((task_id, func, args, kwargs))
        return task_id

    def _worker(self):
        while self._running:
            try:
                task_id, func, args, kwargs = self._queue.get(timeout=0.5)
            except queue.Empty:
                continue
            try:
                result = func(*args, **kwargs)
                with self._lock:
                    self._results[task_id] = ('ok', result)
            except Exception as exc:
                with self._lock:
                    self._results[task_id] = ('error', exc)
            finally:
                self._queue.task_done()
            time.sleep(self._interval)

    def start(self):
        """Start the executor worker thread."""
        self._running = True
        self._thread = threading.Thread(target=self._worker, daemon=True)
        self._thread.start()

    def stop(self):
        """Stop the executor and wait for pending tasks."""
        self._running = False
        if self._thread:
            self._thread.join()

    def get_result(self, task_id, timeout=30):
        """Get result for task_id. Blocks until available or timeout."""
        deadline = time.monotonic() + timeout
        while time.monotonic() < deadline:
            with self._lock:
                if task_id in self._results:
                    return self._results.pop(task_id)
            time.sleep(0.05)
        raise TimeoutError('Task ' + str(task_id) + ' did not complete in time')

