class {{nama_class}}:
    """Timeout context manager.
    Uses signal.SIGALRM on Unix, threading fallback on Windows.
    Usage: with timeout(5): do_something()
    """
    def __init__(self, seconds, message='Operation timed out'):
        self.seconds = seconds
        self.message = message

    def __enter__(self):
        try:
            self._old_handler = signal.signal(signal.SIGALRM, self._handler)
            signal.alarm(self.seconds)
            self._use_signal = True
        except (AttributeError, OSError):
            self._use_signal = False
            self._timer = threading.Timer(self.seconds, self._timer_handler)
            self._timer.daemon = True
            self._timer.start()
        return self

    def __exit__(self, *exc):
        if self._use_signal:
            signal.alarm(0)
            signal.signal(signal.SIGALRM, self._old_handler)
        else:
            self._timer.cancel()

    def _handler(self, signum, frame):
        raise {{exception_name}}(self.message)

    def _timer_handler(self):
        raise {{exception_name}}(self.message)

class {{nama_class}}:
    """Limit concurrent operations. Usable as context manager or decorator."""
    def __init__(self, max_concurrent={{max_concurrent}}):
        self._semaphore = threading.Semaphore(max_concurrent)
        self.max_concurrent = max_concurrent
        self._active = 0
        self._lock = threading.Lock()

    def __enter__(self):
        self._semaphore.acquire()
        with self._lock:
            self._active += 1
        return self

    def __exit__(self, *exc):
        with self._lock:
            self._active -= 1
        self._semaphore.release()

    def __call__(self, func):
        """Use as decorator to limit concurrent calls to func."""
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            with self:
                return func(*args, **kwargs)
        return wrapper

    @property
    def active_count(self):
        with self._lock:
            return self._active

class {{nama_class}}:
    """Thread pool executor with bounded task queue.
    Raises RuntimeError if queue is full instead of blocking.
    """
    class QueueFull(Exception):
        """Raised when the task queue is full."""
        pass

    def __init__(self, max_workers={{max_workers}}, max_queued={{max_queued}}):
        self._executor = concurrent.futures.ThreadPoolExecutor(max_workers=max_workers)
        self._semaphore = threading.Semaphore(max_queued)

    def submit(self, fn, *args, **kwargs):
        """Submit task. Raises QueueFull if queue is at capacity."""
        import threading
        if not self._semaphore.acquire(blocking=False):
            raise self.QueueFull('Task queue is full')
        future = self._executor.submit(fn, *args, **kwargs)
        future.add_done_callback(lambda f: self._semaphore.release())
        return future

    def map(self, fn, *iterables, timeout=None):
        """Map function across iterables (blocking)."""
        return self._executor.map(fn, *iterables, timeout=timeout)

    def shutdown(self, wait=True):
        """Shutdown the executor."""
        self._executor.shutdown(wait=wait)

    def __enter__(self):
        return self

    def __exit__(self, *exc):
        self.shutdown()

def {{nama_decorator}}(interval={{default_interval}}):
    """Throttle decorator: function can only be called once per interval seconds.
    Calls within the interval are silently dropped.
    """
    def decorator(func):
        lock = threading.Lock()
        last_call = [0.0]

        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            now = time.monotonic()
            with lock:
                elapsed = now - last_call[0]
                if elapsed < interval:
                    return None
                last_call[0] = now
            return func(*args, **kwargs)

        def reset():
            with lock:
                last_call[0] = 0.0

        wrapper.reset = reset
        return wrapper
    return decorator
